1	import type { Express, Request, Response } from "express";
2	import { Router } from "express";
3	import { v4 as uuid } from "uuid";
4	import { findAll, findById, insert, update } from "../../db.js";
5	import { authorize, getCurrentUser, requireLogin } from "../../shared/auth.js";
6	
7	type ReportType = "rider_report" | "race_report" | "review_summary";
8	type ReportStatus = "draft" | "generated" | "reviewed" | "published";
9	type Visibility = "private" | "public";
10	
11	interface Report {
12	  id: string;
13	  race_id: string;
14	  type: ReportType;
15	  subject_registration_id: string | null;
16	  status: ReportStatus;
17	  visibility: Visibility;
18	  title: string;
19	  summary: string;
20	  body: string;
21	  sections: ReportSection[];
22	  cited_evidence_ids: string[];
23	  cited_award_ids: string[];
24	  source_counts: Record<string, number>;
25	  generated_at: string;
26	  published_at: string | null;
27	  created_by_user_id: string;
28	  updated_by_user_id: string;
29	  created_at: string;
30	  updated_at: string;
31	}
32	
33	interface ReportSection {
34	  heading: string;
35	  body: string;
36	}
37	
38	interface GeneratedReportContent {
39	  title: string;
40	  summary: string;
41	  body: string;
42	  sections: ReportSection[];
43	  citedEvidenceIds: string[];
44	  citedAwardIds: string[];
45	  sourceCounts: Record<string, number>;
46	}
47	
48	type GeneratedReportDraft = Omit<GeneratedReportContent, "body">;
49	
50	const REPORT_TYPES: ReportType[] = ["rider_report", "race_report", "review_summary"];
51	
52	export function registerReportGenRoutes(app: Express): void {
53	  const router = Router();
54	
55	  router.get("/", (req: Request, res: Response) => {
56	    const reports = findAll<Report>("reports");
57	    const currentUser = getCurrentUser(req);
58	    const raceId = asOptionalString(req.query.raceId);
59	    const raceSlug = asOptionalString(req.query.raceSlug);
60	    const type = asOptionalString(req.query.type) as ReportType | undefined;
61	
62	    const filtered = reports
63	      .filter(report => !raceId || report.race_id === raceId)
64	      .filter(report => !raceSlug || getRaceSlug(report.race_id) === raceSlug)
65	      .filter(report => !type || report.type === type)
66	      .filter(report => canReadReport(report, currentUser))
67	      .sort((a, b) => b.updated_at.localeCompare(a.updated_at));
68	
69	    res.json(filtered.map(toReportResponse));
70	  });
71	
72	  router.post("/generate", requireLogin, (req: Request, res: Response) => {
73	    const user = getCurrentUser(req);
74	    if (!user) { res.status(401).json({ error: "Not authenticated" }); return; }
75	
76	    const { raceId, type, subjectRegistrationId } = req.body;
77	    if (!raceId || typeof raceId !== "string") {
78	      res.status(400).json({ error: "raceId is required" }); return;
79	    }
80	    if (!REPORT_TYPES.includes(type)) {
81	      res.status(400).json({ error: "type must be rider_report, race_report, or review_summary" }); return;
82	    }
83	
84	    const race = findById<any>("races", raceId);
85	    if (!race) { res.status(404).json({ error: "Race not found" }); return; }
86	
87	    const validation = validateSubject(type, subjectRegistrationId, raceId);
88	    if (!validation.ok) { res.status(400).json({ error: validation.error }); return; }
89	
90	    const auth = authorize(user, "Report", "generate", {
91	      raceOrganizerIds: getRaceOrganizerIds(race),
92	    });
93	    if (!auth.allowed) { res.status(403).json({ error: auth.reason }); return; }
94	
95	    const now = new Date().toISOString();
96	    const content = buildReportContent(type, race, validation.subjectRegistrationId);
97	    const report: Report = {
98	      id: uuid(),
99	      race_id: raceId,
100	      type,
101	      subject_registration_id: validation.subjectRegistrationId,
102	      status: "generated",
103	      visibility: "private",
104	      title: content.title,
105	      summary: content.summary,
106	      body: content.body,
107	      sections: content.sections,
108	      cited_evidence_ids: content.citedEvidenceIds,
109	      cited_award_ids: content.citedAwardIds,
110	      source_counts: content.sourceCounts,
111	      generated_at: now,
112	      published_at: null,
113	      created_by_user_id: user.userId,
114	      updated_by_user_id: user.userId,
115	      created_at: now,
116	      updated_at: now,
117	    };
118	
119	    insert("reports", report);
120	    res.status(201).json(toReportResponse(report));
121	  });
122	
123	  router.get("/:id", (req: Request, res: Response) => {
124	    const report = findById<Report>("reports", req.params.id);
125	    if (!report) { res.status(404).json({ error: "Report not found" }); return; }
126	
127	    const user = getCurrentUser(req);
128	    if (!canReadReport(report, user)) {
129	      res.status(user ? 403 : 401).json({ error: user ? "Not allowed to view this report" : "Login required" });
130	      return;
131	    }
132	
133	    res.json(toReportResponse(report));
134	  });
135	
136	  router.patch("/:id", requireLogin, (req: Request, res: Response) => {
137	    const user = getCurrentUser(req);
138	    if (!user) { res.status(401).json({ error: "Not authenticated" }); return; }
139	
140	    const report = findById<Report>("reports", req.params.id);
141	    if (!report) { res.status(404).json({ error: "Report not found" }); return; }
142	
143	    const race = findById<any>("races", report.race_id);
144	    const auth = authorize(user, "Report", "edit", { raceOrganizerIds: getRaceOrganizerIds(race) });
145	    if (!auth.allowed) { res.status(403).json({ error: auth.reason }); return; }
146	    if (report.status === "published") {
147	      res.status(409).json({ error: "Published reports cannot be edited" }); return;
148	    }
149	
150	    const updates: Partial<Report> = {
151	      updated_by_user_id: user.userId,
152	      updated_at: new Date().toISOString(),
153	    };
154	    if (typeof req.body.title === "string") updates.title = req.body.title;
155	    if (typeof req.body.summary === "string") updates.summary = req.body.summary;
156	    if (typeof req.body.body === "string") updates.body = req.body.body;
157	    if (Array.isArray(req.body.sections)) updates.sections = req.body.sections;
158	    if (req.body.status === "draft" || req.body.status === "generated" || req.body.status === "reviewed") {
159	      updates.status = req.body.status;
160	    }
161	
162	    const updated = update<Report>("reports", report.id, updates);
163	    res.json(toReportResponse(updated!));
164	  });
165	
166	  router.post("/:id/publish", requireLogin, (req: Request, res: Response) => {
167	    const user = getCurrentUser(req);
168	    if (!user) { res.status(401).json({ error: "Not authenticated" }); return; }
169	
170	    const report = findById<Report>("reports", req.params.id);
171	    if (!report) { res.status(404).json({ error: "Report not found" }); return; }
172	
173	    const race = findById<any>("races", report.race_id);
174	    const auth = authorize(user, "Report", "publish", { raceOrganizerIds: getRaceOrganizerIds(race) });
175	    if (!auth.allowed) { res.status(403).json({ error: auth.reason }); return; }
176	
177	    const now = new Date().toISOString();
178	    const visibility: Visibility = report.type === "rider_report" ? "private" : "public";
179	    const updated = update<Report>("reports", report.id, {
180	      status: "published",
181	      visibility,
182	      published_at: now,
183	      updated_by_user_id: user.userId,
184	      updated_at: now,
185	    });
186	
187	    res.json(toReportResponse(updated!));
188	  });
189	
190	  app.use("/reports", router);
191	  console.log("[report-gen] Routes registered: /reports/*");
192	}
