194	function validateSubject(type: ReportType, rawSubjectRegistrationId: unknown, raceId: string) {
195	  if (type === "rider_report") {
196	    if (!rawSubjectRegistrationId || typeof rawSubjectRegistrationId !== "string") {
197	      return { ok: false as const, error: "subjectRegistrationId is required for rider_report" };
198	    }
199	    const registration = findById<any>("registrations", rawSubjectRegistrationId);
200	    if (!registration) return { ok: false as const, error: "Subject registration not found" };
201	    if (getField(registration, "race_id", "raceId") !== raceId) {
202	      return { ok: false as const, error: "subjectRegistrationId must belong to raceId" };
203	    }
204	    return { ok: true as const, subjectRegistrationId: rawSubjectRegistrationId };
205	  }
206	
207	  if (rawSubjectRegistrationId) {
208	    return { ok: false as const, error: "subjectRegistrationId must be empty for race_report and review_summary" };
209	  }
210	  return { ok: true as const, subjectRegistrationId: null };
211	}
212	
213	function canReadReport(report: Report, user: ReturnType<typeof getCurrentUser>): boolean {
214	  if (report.status === "published" && report.visibility === "public" && report.type !== "rider_report") {
215	    const publicAuth = authorize(null, "Report", "view_public_published", {
216	      visibility: "public",
217	      isPublished: true,
218	    });
219	    if (publicAuth.allowed) return true;
220	  }
221	
222	  if (!user) return false;
223	  if (user.roles.includes("admin")) return true;
224	
225	  const race = findById<any>("races", report.race_id);
226	  const managed = authorize(user, "Report", "edit", { raceOrganizerIds: getRaceOrganizerIds(race) });
227	  if (managed.allowed) return true;
228	
229	  if (report.type !== "rider_report" || !report.subject_registration_id) return false;
230	  const registration = findById<any>("registrations", report.subject_registration_id);
231	  const own = authorize(user, "Report", "view_private", {
232	    ownerUserId: getField(registration, "user_id", "userId"),
233	  });
234	  return own.allowed;
235	}
236	
237	function buildReportContent(type: ReportType, race: any, subjectRegistrationId: string | null) {
238	  const raceId = getField(race, "id");
239	  const registrations = findAll<any>("registrations").filter(r => getField(r, "race_id", "raceId") === raceId);
240	  const works = findAll<any>("works").filter(w => registrations.some(r => getField(w, "registration_id", "registrationId") === getField(r, "id")));
241	  const awards = findAll<any>("awards").filter(a => getField(a, "race_id", "raceId") === raceId);
242	  const judgingRecords = findAll<any>("judging_records").filter(j => registrations.some(r => getField(j, "registration_id", "registrationId") === getField(r, "id")));
243	  const evidences = findAll<any>("evidences").filter(e => registrations.some(r => getField(e, "registration_id", "registrationId") === getField(r, "id")));
244	
245	  if (type === "rider_report") {
246	    const registration = registrations.find(r => getField(r, "id") === subjectRegistrationId);
247	    const riderWorks = works.filter(w => getField(w, "registration_id", "registrationId") === subjectRegistrationId);
248	    const riderAwards = awards.filter(a => getField(a, "registration_id", "registrationId") === subjectRegistrationId);
249	    const riderEvidence = evidences.filter(e => getField(e, "registration_id", "registrationId") === subjectRegistrationId);
250	    const riderName = getDisplayName(getField(registration, "user_id", "userId"));
251	    const sections = [
252	      { heading: "参赛表现", body: `${riderName} 在 ${raceTitle(race)} 中提交 ${riderWorks.length} 个作品，获得 ${riderAwards.length} 个奖项记录。` },
253	      { heading: "能力证据", body: `报告引用 ${riderEvidence.length} 条 Evidence 摘要，用于支撑骑行能力、风险处理和复盘判断。` },
254	    ];
255	    return composeContent({
256	      title: `${riderName} 个人成绩单`,
257	      summary: `${raceTitle(race)} 的个人报告草稿，聚合作品、奖项、评审和 Evidence 摘要。`,
258	      sections,
259	      citedEvidenceIds: riderEvidence.map(e => getField(e, "id")).filter(Boolean),
260	      citedAwardIds: riderAwards.map(a => getField(a, "id")).filter(Boolean),
261	      sourceCounts: { registrations: 1, works: riderWorks.length, awards: riderAwards.length, evidences: riderEvidence.length },
262	    });
263	  }
264	
265	  if (type === "race_report") {
266	    const sections = [
267	      { heading: "赛事结果", body: `${raceTitle(race)} 当前聚合 ${registrations.length} 个报名、${works.length} 个作品、${awards.length} 个奖项记录。` },
268	      { heading: "评审输入", body: `报告草稿读取 ${judgingRecords.length} 条评审记录和 ${evidences.length} 条 Evidence 摘要，不读取过程 Projection 作为最终事实。` },
269	    ];
270	    return composeContent({
271	      title: `${raceTitle(race)} 赛事报告`,
272	      summary: "赛事报告草稿聚合最终奖项、作品提交、评审记录和公开证据摘要。",
273	      sections,
274	      citedEvidenceIds: evidences.map(e => getField(e, "id")).filter(Boolean),
275	      citedAwardIds: awards.map(a => getField(a, "id")).filter(Boolean),
276	      sourceCounts: { registrations: registrations.length, works: works.length, awards: awards.length, judgingRecords: judgingRecords.length, evidences: evidences.length },
277	    });
278	  }
279	
280	  const sections = [
281	    { heading: "评审结论", body: `${raceTitle(race)} 的评审总结基于已发布奖项、评审记录和可公开 Evidence 摘要生成。` },
282	    { heading: "复盘重点", body: "总结关注作品完成度、Agent 协作、纠偏能力、成本控制和风险处理表现。主办方发布前应人工复核。"},
283	  ];
284	  return composeContent({
285	    title: `${raceTitle(race)} 评审总结`,
286	    summary: "公开 Review 草稿，用于解释赛果背后的评审判断和复盘价值。",
287	    sections,
288	    citedEvidenceIds: evidences.map(e => getField(e, "id")).filter(Boolean),
289	    citedAwardIds: awards.map(a => getField(a, "id")).filter(Boolean),
290	    sourceCounts: { awards: awards.length, judgingRecords: judgingRecords.length, evidences: evidences.length },
291	  });
292	}
293	
294	function composeContent(input: GeneratedReportDraft): GeneratedReportContent {
295	  return {
296	    ...input,
297	    body: input.sections.map(section => `## ${section.heading}\n${section.body}`).join("\n\n"),
298	  };
299	}
300	
301	function toReportResponse(report: Report) {
302	  return {
303	    id: report.id,
304	    raceId: report.race_id,
305	    raceSlug: getRaceSlug(report.race_id),
306	    type: report.type,
307	    subjectRegistrationId: report.subject_registration_id,
308	    status: report.status,
309	    visibility: report.visibility,
310	    title: report.title,
311	    summary: report.summary,
312	    body: report.body,
313	    sections: report.sections,
314	    citedEvidenceIds: report.cited_evidence_ids,
315	    citedAwardIds: report.cited_award_ids,
316	    sourceCounts: report.source_counts,
317	    generatedAt: report.generated_at,
318	    publishedAt: report.published_at,
319	    createdAt: report.created_at,
320	    updatedAt: report.updated_at,
321	  };
322	}
323	
324	function getRaceOrganizerIds(race: any): string[] | undefined {
325	  if (!race) return undefined;
326	  const ids = getField(race, "organizer_user_ids", "organizerUserIds");
327	  if (Array.isArray(ids)) return ids;
328	  if (typeof ids === "string") {
329	    try {
330	      const parsed = JSON.parse(ids);
331	      return Array.isArray(parsed) ? parsed : undefined;
332	    } catch {
333	      return ids ? [ids] : undefined;
334	    }
335	  }
336	  const createdBy = getField(race, "created_by_user_id", "createdByUserId");
337	  return createdBy ? [createdBy] : undefined;
338	}
339	
340	function getRaceSlug(raceId: string): string | null {
341	  const race = findById<any>("races", raceId);
342	  return race ? getField(race, "slug") ?? null : null;
343	}
344	
345	function raceTitle(race: any): string {
346	  return getField(race, "title", "name") ?? "Untitled Race";
347	}
348	
349	function getDisplayName(userId: string | undefined): string {
350	  if (!userId) return "Unknown Rider";
351	  const user = findById<any>("users", userId);
352	  return getField(user, "displayName", "display_name", "githubAccount", "github_account") ?? "Unknown Rider";
353	}
354	
355	function getField<T = any>(row: any, ...fields: string[]): T | undefined {
356	  if (!row) return undefined;
357	  for (const field of fields) {
358	    if (row[field] !== undefined && row[field] !== null) return row[field] as T;
359	  }
360	  return undefined;
361	}
362	
363	function asOptionalString(value: unknown): string | undefined {
364	  return typeof value === "string" && value.trim() ? value.trim() : undefined;
365	}
