1	import { useParams } from "react-router-dom";
2	import { useEffect, useState } from "react";
3	
4	interface Report {
5	  id: string;
6	  title: string;
7	  summary: string;
8	  sections: { heading: string; body: string }[];
9	  publishedAt: string | null;
10	  sourceCounts: Record<string, number>;
11	}
12	
13	export default function ReviewPage() {
14	  const { slug } = useParams();
15	  const [report, setReport] = useState<Report | null>(null);
16	  const [loading, setLoading] = useState(true);
17	
18	  useEffect(() => {
19	    setLoading(true);
20	    fetch(`/reports?raceSlug=${slug}&type=review_summary`, { credentials: "include" })
21	      .then((res) => (res.ok ? res.json() : []))
22	      .then((rows) => setReport(rows[0] ?? null))
23	      .finally(() => setLoading(false));
24	  }, [slug]);
25	
26	  if (loading) return <div><h1>Review</h1><p>Loading review summary...</p></div>;
27	  if (!report) {
28	    return (
29	      <div>
30	        <h1>Review: {slug}</h1>
31	        <p>评审总结尚未发布。</p>
32	      </div>
33	    );
34	  }
35	
36	  return (
37	    <div style={{ maxWidth: 920, margin: "0 auto" }}>
38	      <p style={{ color: "#53668d", fontWeight: 700 }}>Review Summary</p>
39	      <h1>{report.title}</h1>
40	      <p style={{ fontSize: 18, lineHeight: 1.7 }}>{report.summary}</p>
41	
42	      <section style={{ display: "grid", gap: 16, marginTop: 28 }}>
43	        {report.sections.map((section) => (
44	          <article
45	            key={section.heading}
46	            style={{
47	              padding: 20,
48	              border: "1px solid rgba(34,107,230,0.16)",
49	              borderRadius: 8,
50	              background: "rgba(255,255,255,0.72)",
51	            }}
52	          >
53	            <h2 style={{ marginTop: 0 }}>{section.heading}</h2>
54	            <p style={{ lineHeight: 1.7 }}>{section.body}</p>
55	          </article>
56	        ))}
57	      </section>
58	
59	      <p style={{ marginTop: 24, color: "#53668d" }}>
60	        Published: {report.publishedAt ? new Date(report.publishedAt).toLocaleString() : "pending"}
61	      </p>
62	    </div>
63	  );
64	}
