1	#!/bin/bash
2	set -e
3	
4	BASE="http://localhost:3000"
5	COOKIE="/tmp/ary-report-gen-cookie.txt"
6	REPO_ROOT="$(cd "$(dirname "$0")/../../../.." && pwd)"
7	
8	cleanup() {
9	  REPO_ROOT="$REPO_ROOT" node <<'NODE'
10	const fs = require("fs");
11	const path = require("path");
12	const dataDir = path.join(process.env.REPO_ROOT, "database", "data");
13	function read(name) {
14	  const file = path.join(dataDir, `${name}.json`);
15	  if (!fs.existsSync(file)) return [];
16	  return JSON.parse(fs.readFileSync(file, "utf8"));
17	}
18	function write(name, rows) {
19	  if (!fs.existsSync(dataDir)) return;
20	  fs.writeFileSync(path.join(dataDir, `${name}.json`), JSON.stringify(rows, null, 2));
21	}
22	function removeByIds(name, ids) {
23	  write(name, read(name).filter((row) => !ids.includes(row.id)));
24	}
25	removeByIds("users", ["report-rider-1"]);
26	write("users", read("users").filter((row) => row.githubAccount !== "report-organizer"));
27	removeByIds("races", ["report-race-1"]);
28	removeByIds("registrations", ["report-registration-1"]);
29	removeByIds("works", ["report-work-1"]);
30	removeByIds("judging_records", ["report-judging-1"]);
31	removeByIds("awards", ["report-award-1"]);
32	removeByIds("evidences", ["report-evidence-1"]);
33	write("reports", read("reports").filter((row) => row.race_id !== "report-race-1"));
34	NODE
35	  rm -f "$COOKIE"
36	}
37	
38	trap cleanup EXIT
39	
40	echo "--- E report-gen: login organizer ---"
41	LOGIN=$(curl -s -X POST "$BASE/auth/github" \
42	  -H "Content-Type: application/json" \
43	  -d '{"githubAccount":"report-organizer","displayName":"Report Organizer"}' \
44	  -c "$COOKIE")
45	USER_ID=$(node -e "const data=JSON.parse(process.argv[1]); console.log(data.userId)" "$LOGIN")
46	
47	echo "--- E report-gen: seed dependent mock data ---"
48	REPO_ROOT="$REPO_ROOT" node - "$USER_ID" <<'NODE'
49	const fs = require("fs");
50	const path = require("path");
51	const userId = process.argv[2];
52	const dataDir = path.join(process.env.REPO_ROOT, "database", "data");
53	fs.mkdirSync(dataDir, { recursive: true });
54	
55	function read(name) {
56	  const file = path.join(dataDir, `${name}.json`);
57	  if (!fs.existsSync(file)) return [];
58	  return JSON.parse(fs.readFileSync(file, "utf8"));
59	}
60	function write(name, rows) {
61	  fs.writeFileSync(path.join(dataDir, `${name}.json`), JSON.stringify(rows, null, 2));
62	}
63	function upsert(name, row) {
64	  const rows = read(name).filter((item) => item.id !== row.id);
65	  rows.push(row);
66	  write(name, rows);
67	}
68	
69	const users = read("users").map((u) => u.id === userId ? { ...u, roles: ["organizer"] } : u);
70	write("users", users);
71	
72	upsert("users", { id: "report-rider-1", githubAccount: "report-rider", displayName: "Report Rider", profileCompleted: true, roles: ["rider"], createdAt: new Date().toISOString(), updatedAt: new Date().toISOString() });
73	upsert("races", { id: "report-race-1", slug: "report-race", title: "Report Gen Test Race", organizer_user_ids: [userId], status: "completed" });
